-- CBoard demo seed for Docker MySQL (runs once on first container init).
-- Full FoodMart sample: scripts/load-full-demo.sh (H2 only)

DELETE FROM dashboard_datasource WHERE datasource_id = 1;

DELETE FROM dashboard_dataset WHERE dataset_id = 1;

DROP TABLE IF EXISTS sales_fact_sample_flat;
CREATE TABLE sales_fact_sample_flat (
  the_year INT,
  month_of_year SMALLINT,
  day_of_month SMALLINT,
  the_date TIMESTAMP,
  SALES_DISTRICT VARCHAR(30),
  SALES_REGION VARCHAR(30),
  SALES_COUNTRY VARCHAR(30),
  yearly_income VARCHAR(30) NOT NULL,
  total_children SMALLINT NOT NULL,
  member_card VARCHAR(30),
  num_cars_owned INT,
  gender VARCHAR(30) NOT NULL,
  store_sales DECIMAL(10,4) NOT NULL,
  store_cost DECIMAL(10,4) NOT NULL,
  unit_sales DECIMAL(10,4) NOT NULL
);


SELECT '1', '1', 1, 'write', 'N' WHERE NOT EXISTS (
  SELECT 1 FROM dashboard_role_res WHERE role_id = '1' AND res_type = '1' AND res_id = 1);
SELECT '1', '2', 1, 'write', 'N' WHERE NOT EXISTS (
  SELECT 1 FROM dashboard_role_res WHERE role_id = '1' AND res_type = '2' AND res_id = 1);

